const urlString = $.input.urls || '';
const urls = urlString.split(',').map(u => u.trim()).filter(u => u.length > 0 && (u.startsWith('http://') || u.startsWith('https://')));
return { urls, urlCount: urls.length };

const urls = $.steps.parseUrls.output.urls;
const iterations = $.steps.scrapePages.response.iterations || [];

let allContent = '';
let successCount = 0;
let failCount = 0;
const pageResults = [];

iterations.forEach((iter, i) => {
  const url = urls[i] || 'Unknown';
  const resp = (iter.scrapePage && iter.scrapePage.response && iter.scrapePage.response.data) ? iter.scrapePage.response.data : null;

  if (resp && resp.markdown) {
    successCount++;
    const md = resp.markdown.slice(0, 3000);
    allContent += '=== PAGE ' + (i + 1) + ' ===\n';
    allContent += 'URL: ' + url + '\n';
    allContent += 'Content:\n' + md + '\n\n';
    pageResults.push({ index: i + 1, url, status: 'success', contentLength: resp.markdown.length });
  } else {
    failCount++;
    allContent += '=== PAGE ' + (i + 1) + ' (FAILED) ===\n';
    allContent += 'URL: ' + url + '\n';
    allContent += 'Status: Failed to scrape\n\n';
    pageResults.push({ index: i + 1, url, status: 'failed', contentLength: 0 });
  }
});

return { allContent, successCount, failCount, totalPages: urls.length, pageResults };

const data = $.steps.compileAllPages.output;
const goal = $.input.extractionGoal || 'Extract all structured data, key facts, and notable information';

let prompt = 'You are a web data extraction and analysis specialist. You have been given content scraped from multiple web pages. Analyze all pages and compile a comprehensive summary.\n\n';
prompt += 'EXTRACTION GOAL: ' + goal + '\n';
prompt += 'TOTAL PAGES SCRAPED: ' + data.successCount + ' of ' + data.totalPages + '\n\n';
prompt += 'SCRAPED CONTENT:\n' + data.allContent + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Extract and organize the key data from each page\n';
prompt += '- Identify patterns, trends, or commonalities across pages\n';
prompt += '- Compile a unified summary of all extracted information\n';
prompt += '- Note any pages that had unique or standout data\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "overallSummary": "2-3 sentence summary across all pages",\n';
prompt += '  "pagesAnalyzed": [\n';
prompt += '    { "pageNumber": 1, "url": "url", "title": "inferred page title", "keyData": ["data point 1", "data point 2"], "notableFindings": "anything special" }\n';
prompt += '  ],\n';
prompt += '  "crossPageInsights": ["insight that spans multiple pages"],\n';
prompt += '  "extractedData": [{ "category": "category name", "items": ["item1", "item2"] }],\n';
prompt += '  "totalDataPoints": 0\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { overallSummary: raw, pagesAnalyzed: [], crossPageInsights: [], extractedData: [], totalDataPoints: 0 }; }

const ai = $.steps.parseAI.output;
const stats = $.steps.compileAllPages.output;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Multi-Page Scraping Report', emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Pages Scraped:*\n' + stats.successCount + ' of ' + stats.totalPages },
  { type: 'mrkdwn', text: '*Data Points:*\n' + (ai.totalDataPoints || 'N/A') }
] });
blocks.push({ type: 'divider' });

const summaryText = (ai.overallSummary || 'No summary generated.').slice(0, 1800);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary:*\n' + summaryText } });

if (ai.pagesAnalyzed && ai.pagesAnalyzed.length > 0) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Page Results:*' } });
  ai.pagesAnalyzed.slice(0, 8).forEach(p => {
    let pageText = '*' + p.pageNumber + '. ' + (p.title || 'Page') + '*';
    pageText += '\n<' + p.url + '|View Page>';
    if (p.keyData && p.keyData.length > 0) {
      pageText += '\n' + p.keyData.slice(0, 3).map(d => '  - ' + d).join('\n');
    }
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: pageText.slice(0, 1800) } });
  });
}

if (ai.crossPageInsights && ai.crossPageInsights.length > 0) {
  blocks.push({ type: 'divider' });
  let insightText = '*Cross-Page Insights:*\n';
  ai.crossPageInsights.slice(0, 5).forEach((ins, i) => { insightText += (i + 1) + '. ' + ins + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: insightText.slice(0, 1800) } });
}

if (stats.failCount > 0) {
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':warning: ' + stats.failCount + ' page(s) failed to scrape' }] });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Firecrawl + Claude AI' }] });

const fallbackText = 'Multi-Page Scraping: ' + stats.successCount + '/' + stats.totalPages + ' pages scraped - ' + (ai.overallSummary || '').slice(0, 100);
return { blocks, fallbackText };
